&NewLine;

[MATH text=p\_{n,k}=p\_{n-1,k}+p\_{n-1,k-1}],

&NewLine;

kun[MATH text= n\ge 2] ja [MATH text=0<k<n]. Huomaa, että indeksien [MATH text=n] ja [MATH text=k] numerointi alkaa nollasta.

&NewLine;

